/**
 * A module for importing types used in [sql](https://developers.arcgis.com/javascript/latest/references/core/core/sql/) and [WhereClause](https://developers.arcgis.com/javascript/latest/references/core/core/sql/WhereClause/) modules.
 *
 * @since 5.0
 */

/**
 * The position in the original SQL expression string for a SQL node in the parse tree returned by
 * [WhereClause.parseTree](https://developers.arcgis.com/javascript/latest/references/core/core/sql/WhereClause/#parseTree).
 *
 * @see [WhereClause.parseTree](https://developers.arcgis.com/javascript/latest/references/core/core/sql/WhereClause/#parseTree)
 * @since 5.0
 */
export interface SourcePosition {
  /**
   * The 0-based character offset in the original SQL string where the node starts.
   *
   * Together with `line` and `column`, this allows precise mapping
   * of the parse tree node back to its position in the source.
   *
   * @since 5.0
   */
  offset: number;
  /**
   * The 1-based line number in the original SQL string at which the node starts.
   *
   * @since 5.0
   */
  line: number;
  /**
   * The 1-based column number in the original SQL string at which the node starts.
   *
   * @since 5.0
   */
  column: number;
}

/**
 * A source location range in the original SQL string.
 *
 * The location spans from [SQLSourceLocation](https://developers.arcgis.com/javascript/latest/references/core/core/sql/types/#SQLSourceLocation-start) (inclusive) to
 * [SQLSourceLocation](https://developers.arcgis.com/javascript/latest/references/core/core/sql/types/#SQLSourceLocation-end) (exclusive).
 *
 * @since 5.0
 */
export interface SQLSourceLocation {
  /** @since 5.0 */
  source?: unknown;
  /**
   * The inclusive start position of the range.
   *
   * @since 5.0
   */
  start: SourcePosition;
  /**
   * The exclusive end position of the range.
   *
   * @since 5.0
   */
  end: SourcePosition;
}

/**
 * Error thrown when a SQL expression cannot be [parsed](https://developers.arcgis.com/javascript/latest/references/core/core/sql/WhereClause/#parseTree).
 *
 * @since 5.0
 */
export interface SQLSyntaxError extends Error {
  /**
   * The syntax error name. It is always `"SyntaxError"`.
   *
   * @since 5.0
   */
  name: "SyntaxError";
  /**
   * A description of the parse error.
   *
   * @since 5.0
   */
  message: string;
  /**
   * The location in the original SQL string associated with the parse error.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
}

/**
 * A minimal feature/attributes object used by [WhereClause.calculateValue()](https://developers.arcgis.com/javascript/latest/references/core/core/sql/WhereClause/#calculateValue) or [WhereClause.testFeature()](https://developers.arcgis.com/javascript/latest/references/core/core/sql/WhereClause/#testFeature).
 * The where clause evaluator can read attribute values from either:
 * - A plain object (for example, `{ POPULATION: 300000 }`), or
 * - An object containing an `attributes` property (for example,
 *   `{ attributes: { POPULATION: 300000 } }`, such as a [Graphic](https://developers.arcgis.com/javascript/latest/references/core/Graphic/)).
 *
 * @since 5.0
 */
export type SimpleAttributes = { attributes: Record<string, unknown>; } | Record<string, any>;

/**
 * SQL parse tree is composed of SqlNodes. It may be an operator, literal, function, list, and so forth.
 *
 * @since 4.24
 */
export type SQLNode = BinaryNode | BoolNode | ColumnNode | CurrentTimeNode | CurrentUserNode | DataTypeNode | DateNode | FunctionNode | IntervalNode | IntervalPeriodNode | IntervalQualifierNode | ListNode | NullNode | NumberNode | ParamNode | SearchedCaseNode | SimpleCaseNode | StringNode | TimeNode | TimeStampNode | UnaryNode | WhenNode;

/**
 * A simple case expression node. This represents expressions of the form:
 *
 * `CASE <operand> WHEN <whenOperand> THEN <result> ... [ELSE <elseResult>] END`
 *
 * During evaluation, the `operand` value is compared to each
 * `WHEN` operand using equality. The first matching clause determines the result. If no clause matches,
 * the `ELSE` expression is used when present, otherwise the result is `null`.
 *
 * @since 4.24
 */
export interface SimpleCaseNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "case-expression";
  /**
   * Location of the full `CASE ... END` expression.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The case expression format. Value for this property is always `"simple"`.
   *
   * @since 5.0
   */
  format: "simple";
  /**
   * Ordered `WHEN ... THEN ...` clauses.
   * Each clause's [WhenNode.operand](https://developers.arcgis.com/javascript/latest/references/core/core/sql/types/#WhenNode) is compared against the
   * SimpleCaseNode's `operand`, and the matching clause's
   * [WhenNode.value](https://developers.arcgis.com/javascript/latest/references/core/core/sql/types/#WhenNode) determines the result.
   *
   * @since 5.0
   */
  clauses: WhenNode[];
  /**
   * The expression following the `CASE` keyword.
   * This value is compared to each clause operand.
   *
   * @since 5.0
   */
  operand: SQLNode;
  /**
   * The `ELSE` result expression, or `null` if the `ELSE` clause is not present.
   *
   * @since 5.0
   */
  else: SQLNode | null;
  /**
   * Location of the `ELSE` keyword and result expression, or `null` if the `ELSE` clause is not present.
   *
   * @since 5.0
   */
  elseLocation: SQLSourceLocation | null;
}

/**
 * A searched `CASE` expression node.
 * Represents expressions of the form:
 *
 * `CASE WHEN <condition> THEN <result> ... [ELSE <elseResult>] END`
 *
 * During evaluation, each `WHEN` condition is evaluated in order.
 * The result of the first condition that evaluates to `true` is returned.
 * If no condition matches, the `ELSE` expression is evaluated if present; otherwise, the result is `null`.
 *
 * @since 4.24
 */
export interface SearchedCaseNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "case-expression";
  /**
   * Location of the full `CASE ... END` expression.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The case expression format. Value for this property is always `"searched"`.
   *
   * @since 5.0
   */
  format: "searched";
  /**
   * Ordered `WHEN ... THEN ...` clauses.
   *
   * Each clause's [WhenNode.operand](https://developers.arcgis.com/javascript/latest/references/core/core/sql/types/#WhenNode) is evaluated as a condition, and the
   * first clause whose condition evaluates to `true` determines the result.
   *
   * @since 5.0
   */
  clauses: WhenNode[];
  /**
   * The `ELSE` result expression, or `null` if the `ELSE` clause is not present.
   *
   * @since 5.0
   */
  else: SQLNode | null;
  /**
   * Location of the `ELSE` keyword and result expression, or `null` if the `ELSE` clause is not present.
   *
   * @since 5.0
   */
  elseLocation: SQLSourceLocation | null;
}

/**
 * A `WHEN ... THEN ...` clause in a `CASE` expression.
 * This node is used by both [SimpleCaseNode](https://developers.arcgis.com/javascript/latest/references/core/core/sql/types/#SimpleCaseNode) and
 * [SearchedCaseNode](https://developers.arcgis.com/javascript/latest/references/core/core/sql/types/#SearchedCaseNode):
 * - In a simple case expression, WhenNode's `operand` is compared against the simple case operand.
 * - In a searched case expression, WhenNode's `operand` is evaluated as a condition.
 *
 * When the clause matches, WhenNode's `value` determines the result.
 *
 * @since 4.24
 */
export interface WhenNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "when-clause";
  /**
   * Location of the full `WHEN ... THEN ...` clause.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The expression following the `WHEN` keyword.
   * In simple case expressions, this expression is compared against the case operand.
   * In searched case expressions, this expression is evaluated as a condition.
   *
   * @since 5.0
   */
  operand: SQLNode;
  /**
   * The expression following the `THEN` keyword.
   * This expression determines the result when the clause matches.
   *
   * @since 5.0
   */
  value: SQLNode;
}

/**
 * A parameter reference node. Parameter references use the `@name` syntax in SQL expressions.
 *
 * @since 4.24
 */
export interface ParamNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "parameter";
  /**
   * Location of the full `@name` parameter reference.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The parameter name without the leading `@`.
   * The name is matched against parameters using a case-insensitive lookup.
   *
   * @since 5.0
   */
  value: string;
}

/**
 * An ordered list of SQL expressions.
 * This node is commonly produced for parenthesized expression lists (for example, function call
 * arguments or `IN (<expr>, <expr>, ...)` lists). It is also used for other constructs that naturally
 * form an ordered set of expressions (for example, `BETWEEN <begin> AND <end>`).
 *
 * @since 4.24
 */
export interface ListNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "expression-list";
  /**
   * Location of the full list expression.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The expressions in the list, in source order.
   *
   * @since 5.0
   */
  value: SQLNode[];
}

/**
 * A node that contains unary operator. Unary operators can be applied only to expressions that evaluate to any one of the data types of
 * the numeric data type category.
 *
 * @since 4.24
 */
export interface UnaryNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "unary-expression";
  /**
   * Location of the full unary node.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The unary operator. Value for this property is always `"NOT"` since it is the only unary operator supported in SQL expressions.
   *
   * @since 5.0
   */
  operator: "NOT";
  /**
   * The sql node.
   *
   * @since 5.0
   */
  expr: SQLNode;
}

/**
 * A binary expression node. It is an operator that defines the way two expressions are combined to yield a single result.
 * It can be an arithmetic operator, the assignment operator (=), a comparison operator (>=), a logical operator (AND),
 * or a string concatenation operator (+).
 *
 * @since 4.24
 */
export interface BinaryNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "binary-expression";
  /**
   * Location of the full binary node.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * Defines the way two expressions are combined to yield a single result.
   *
   * @since 5.0
   */
  operator: BinaryOperator;
  /**
   * SQL node to the left of the binary node.
   *
   * @since 5.0
   */
  left: SQLNode;
  /**
   * SQL node to the right of the binary node.
   *
   * @since 5.0
   */
  right: SQLNode;
  /**
   * Escape string.
   *
   * @since 5.0
   */
  escape?: string;
}

/**
 * A node that contains `NULL` value.
 *
 * @since 4.24
 */
export interface NullNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "null";
  /**
   * Location of the `NULL` literal in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * Null value.
   *
   * @since 5.0
   */
  value: null;
}

/**
 * A node that contains a boolean expression. Used for expressing a condition or criterion which can be either true or false.
 *
 * @since 4.24
 */
export interface BoolNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "boolean";
  /**
   * Location of the boolean literal in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * Values are `true` or `false`.
   *
   * @since 5.0
   */
  value: boolean;
}

/**
 * A node that contains string.
 *
 * @since 4.24
 */
export interface StringNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "string";
  /**
   * Location of the string literal in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The string value.
   *
   * @since 5.0
   */
  value: string;
}

/**
 * A node that contains number.
 *
 * @since 4.24
 */
export interface NumberNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "number";
  /**
   * Location of the number literal in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * Numeric value.
   *
   * @since 5.0
   */
  value: number;
}

/**
 * A node that contains date.
 *
 * @since 4.24
 */
export interface DateNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "date";
  /**
   * Location of the date literal in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The date value.
   *
   * @since 5.0
   */
  value: string;
}

/**
 * A node that contains time.
 *
 * @since 4.24
 */
export interface TimeNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "time";
  /**
   * Location of the time literal in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The time value.
   *
   * @since 5.0
   */
  value: string;
}

/**
 * A node that contains date.
 *
 * @since 4.24
 */
export interface TimeStampNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "timestamp";
  /**
   * Location of the timestamp literal in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * String date value.
   *
   * @since 5.0
   */
  value: string;
}

/**
 * A node that contains column name of a layer or table.
 *
 * @since 4.24
 */
export interface ColumnNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "column-reference";
  /**
   * Location of the column name in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * Column or field name.
   *
   * @since 5.0
   */
  column: string;
}

/**
 * A node that contains `CURRENT_TIMESTAMP`, `CURRENT_TIME`, or `CURRENT_DATE` functions.
 *
 * @since 4.24
 */
export interface CurrentTimeNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "current-time";
  /**
   * Location of the current time function in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The current time node mode.
   *
   * @since 5.0
   */
  mode: "timestamp" | "date" | "time";
}

/**
 * A node that contains `CURRENT_USER` function.
 *
 * @since 4.31
 */
export interface CurrentUserNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "current-user";
  /**
   * Location of the current user function in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
}

/**
 * Interval node indicates that the character literal is an interval.
 * An interval is defined as the difference between two dates and times.
 *
 * @since 4.24
 */
export interface IntervalNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "interval";
  /**
   * Location of the interval expression in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * Interval node value.
   *
   * @since 5.0
   */
  value: StringNode | ParamNode;
  /**
   * Interval node sign.
   *
   * @since 5.0
   */
  op: "+" | "-" | "";
  /**
   * The interval qualifier
   * can either be a single datetime field or be composed of two datetime fields, in the form: `<leading field> TO <trailing field>`.
   *
   * @since 5.0
   */
  qualifier: IntervalQualifierNode | IntervalPeriodNode;
}

/**
 * Node that contains interval qualifier. The interval qualifier can either be a single datetime field or be composed of two datetime fields,
 * in the form: `<leading field> TO <trailing field>`.
 *
 * @since 4.24
 */
export interface IntervalQualifierNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "interval-qualifier";
  /**
   * Location of the interval qualifier in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * The start interval node period.
   *
   * @since 5.0
   */
  start: IntervalPeriodNode;
  /**
   * The end interval node period.
   *
   * @since 5.0
   */
  end: IntervalPeriodNode;
}

/**
 * Interval period node.
 *
 * @since 4.24
 */
export interface IntervalPeriodNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "interval-period";
  /**
   * Location of the interval period in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * Interval node periods.
   *
   * @since 5.0
   */
  period: "day" | "month" | "hour" | "second" | "year" | "minute";
  /**
   * Precision for an interval data type includes interval leading precision, interval precision, and seconds precision.
   *
   * @since 5.0
   */
  precision: number | null;
  /**
   * Seconds precision.
   *
   * @since 5.0
   */
  secondary: number | null;
}

/**
 * A nodes that contains SQL function.
 *
 * @since 4.24
 */
export interface FunctionNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "function";
  /**
   * Location of the SQL function in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /**
   * Name of the SQL function.
   *
   * @since 5.0
   */
  name: string;
  /**
   * Function arguments.
   *
   * @since 5.0
   */
  args: ListNode;
}

/**
 * A binary operator that defines the way two expressions are combined to yield a single result.
 *
 * @since 5.0
 */
export type BinaryOperator = "AND" | "OR" | "IS" | "ISNOT" | "IN" | "NOT IN" | "BETWEEN" | "NOTBETWEEN" | "LIKE" | "NOT LIKE" | "<>" | "<" | ">" | ">=" | "<=" | "=" | "*" | "-" | "+" | "/" | "||";

/**
 * A node that contains data type. It is used in CAST expressions.
 *
 * @since 4.26
 */
export interface DataTypeNode {
  /**
   * SQL node type.
   *
   * @since 5.0
   */
  type: "data-type";
  /**
   * Location of the data type in the original SQL string.
   *
   * @since 5.0
   */
  location: SQLSourceLocation;
  /** @since 5.0 */
  value: DataTypeNodeValue;
}

/**
 * Data type node value. It contains the name of the data type and an optional size for character types.
 *
 * @since 5.0
 */
export interface DataTypeNodeValue {
  /**
   * The name of the data type.
   *
   * @since 5.0
   */
  type: "integer" | "real" | "smallint" | "float" | "date" | "timestamp" | "varchar" | "time";
  /**
   * Size of the data type. It is applicable for character types such as `varchar`.
   *
   * @since 5.0
   */
  size?: number;
}